#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

void lud_diagonal(float *m, int matrix_dim, int offset) {
    int i, j, tx;
    float shadow[BLOCK_SIZE * BLOCK_SIZE];

    // Load shadow matrix
#pragma omp parallel for private(i, tx) shared(m, shadow, matrix_dim, offset)
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int array_offset = offset * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            shadow[i * BLOCK_SIZE + tx] = m[array_offset + tx];
            array_offset += matrix_dim;
        }
    }

#pragma omp barrier

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        // Update lower triangle
#pragma omp parallel for private(j, tx) shared(shadow, i)
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            if (i < tx) {
                for (j = 0; j < i; j++)
                    shadow[tx * BLOCK_SIZE + i] -= shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
                shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
            }
        }

#pragma omp barrier

        // Update upper triangle
#pragma omp parallel for private(j, tx) shared(shadow, i)
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            if (tx > i) {
                for (j = 0; j < i + 1; j++)
                    shadow[(i + 1) * BLOCK_SIZE + tx] -= shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
            }
        }

#pragma omp barrier
    }

    // Write back to global memory
#pragma omp parallel for private(i, tx) shared(m, shadow, matrix_dim, offset)
    for (i = 1; i < BLOCK_SIZE; i++) {
        int array_offset = (offset + i) * matrix_dim + offset;
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            m[array_offset + tx] = shadow[i * BLOCK_SIZE + tx];
        }
    }
}

void lud_perimeter(float *m, int matrix_dim, int offset) {
    int i, j, tx;
    int bx = 0; // Simulate get_group_id(0) as 0

    float dia[BLOCK_SIZE * BLOCK_SIZE];
    float peri_row[BLOCK_SIZE * BLOCK_SIZE];
    float peri_col[BLOCK_SIZE * BLOCK_SIZE];

    // Load dia, peri_row, peri_col
#pragma omp parallel for private(i, tx) shared(m, dia, peri_row, peri_col, matrix_dim, offset, bx)
    for (tx = 0; tx < 2 * BLOCK_SIZE; tx++) {
        if (tx < BLOCK_SIZE) {
            int idx = tx;
            int array_offset = offset * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE / 2; i++) {
                dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                array_offset += matrix_dim;
            }

            array_offset = offset * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE; i++) {
                peri_row[i * BLOCK_SIZE + idx] = m[array_offset + (bx + 1) * BLOCK_SIZE + idx];
                array_offset += matrix_dim;
            }
        } else {
            int idx = tx - BLOCK_SIZE;
            int array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
            for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
                dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                array_offset += matrix_dim;
            }

            array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE; i++) {
                peri_col[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                array_offset += matrix_dim;
            }
        }
    }

#pragma omp barrier

    // Compute peri_row
#pragma omp parallel for private(i, j, tx) shared(peri_row, dia)
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (j = 0; j < i; j++) {
                peri_row[i * BLOCK_SIZE + tx] -= dia[i * BLOCK_SIZE + j] * peri_row[j * BLOCK_SIZE + tx];
            }
        }
    }

    // Compute peri_col
#pragma omp parallel for private(i, j, tx) shared(peri_col, dia)
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < i; j++) {
                peri_col[tx * BLOCK_SIZE + i] -= peri_col[tx * BLOCK_SIZE + j] * dia[j * BLOCK_SIZE + i];
            }
            peri_col[tx * BLOCK_SIZE + i] /= dia[i * BLOCK_SIZE + i];
        }
    }

#pragma omp barrier

    // Write back peri_row
#pragma omp parallel for private(i, tx) shared(m, peri_row, matrix_dim, offset, bx)
    for (i = 1; i < BLOCK_SIZE; i++) {
        int array_offset = (offset + i) * matrix_dim + offset;
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            m[array_offset + (bx + 1) * BLOCK_SIZE + tx] = peri_row[i * BLOCK_SIZE + tx];
        }
    }

    // Write back peri_col
#pragma omp parallel for private(i, tx) shared(m, peri_col, matrix_dim, offset, bx)
    for (i = 0; i < BLOCK_SIZE; i++) {
        int array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            m[array_offset + tx] = peri_col[i * BLOCK_SIZE + tx];
        }
    }
}

void lud_internal(float *m, int matrix_dim, int offset) {
    int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;
    if (num_blocks <= 0) return;

#pragma omp parallel for collapse(2) schedule(static)
    for (int by = 0; by < num_blocks; by++) {
        for (int bx = 0; bx < num_blocks; bx++) {
            int i, tx, ty, k;
            int global_row_id = offset + (by + 1) * BLOCK_SIZE;
            int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

            float peri_row[BLOCK_SIZE * BLOCK_SIZE];
            float peri_col[BLOCK_SIZE * BLOCK_SIZE];

            // Load peri_row and peri_col
            for (ty = 0; ty < BLOCK_SIZE; ty++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    peri_row[ty * BLOCK_SIZE + tx] = m[(offset + ty) * matrix_dim + global_col_id + tx];
                    peri_col[ty * BLOCK_SIZE + tx] = m[(global_row_id + ty) * matrix_dim + offset + tx];
                }
            }

            // Compute and update internal block
            for (ty = 0; ty < BLOCK_SIZE; ty++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    float sum = 0;
                    for (k = 0; k < BLOCK_SIZE; k++) {
                        sum += peri_col[ty * BLOCK_SIZE + k] * peri_row[k * BLOCK_SIZE + tx];
                    }
                    m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
                }
            }
        }
    }
}

void lud_omp(float *m, int matrix_dim) {
    int i;
    int max_i = matrix_dim - BLOCK_SIZE;
    for (i = 0; i < max_i; i += BLOCK_SIZE) {
        lud_diagonal(m, matrix_dim, i);

        int perimeter_blocks = (matrix_dim - i) / BLOCK_SIZE - 1;
        if (perimeter_blocks > 0) {
            lud_perimeter(m, matrix_dim, i);
            lud_internal(m, matrix_dim, i);
        }
    }
    // Last diagonal block
    lud_diagonal(m, matrix_dim, i);
}
